20	// recordingWaker captures every WakeProject(projectRoot) call. Used to
21	// assert that operatorPromptApprove and operatorPromptSubmit (auto-approve)
22	// signal the local execute-loop coordinator, satisfying the wake-on-approve
23	// AC of S15-5.
24	type recordingWaker struct {
25		mu    sync.Mutex
26		calls []string
27		count int32
28	}
29	
30	func (w *recordingWaker) WakeProject(projectRoot string) int {
31		w.mu.Lock()
32		w.calls = append(w.calls, projectRoot)
33		w.mu.Unlock()
34		atomic.AddInt32(&w.count, 1)
35		return 1
36	}
37	
38	func (w *recordingWaker) Calls() []string {
39		w.mu.Lock()
40		defer w.mu.Unlock()
41		return append([]string(nil), w.calls...)
42	}
