88	// AC: "Execute-loop wakes on approve event without waiting for next tick".
89	// The resolver must call WakeProject after a successful manual approve so
90	// the local execute-loop drops its idle-poll sleep and re-scans the queue.
91	func TestOperatorPromptApprove_SignalsWake(t *testing.T) {
92		waker := &recordingWaker{}
93		h, _, token, workDir := setupWakeHarness(t, []string{ddxgraphql.OperatorPromptAllowlistLocalhostSentinel}, waker)
94	
95		id, _ := submitProposed(t, h, token, "wake me", "k1", nil)
96		if got := atomic.LoadInt32(&waker.count); got != 0 {
97			t.Fatalf("submit without auto-approve must not wake; got %d wakes", got)
98		}
99	
100		resp := postGQL(t, h, token, approveMutation, map[string]any{"id": id})
101		if errs, ok := resp["errors"]; ok {
102			t.Fatalf("approve returned errors: %s", errs)
103		}
104		calls := waker.Calls()
105		if len(calls) != 1 {
106			t.Fatalf("approve must signal exactly one wake; got %v", calls)
107		}
108		if calls[0] != workDir {
109			t.Errorf("wake project root: want %q, got %q", workDir, calls[0])
110		}
111	}
